import{_ as e,W as o,X as p,Y as n,Z as a,$ as t,a1 as i,D as c}from"./framework-ab2cdc09.js";const l={},u=i(`<p>最近工作中遇到的一个问题，网络组把网络设备的“陈年”老日志传到ELK，这样的问题就是日志的时间是过去的，但是logstash在生成时间戳然后输入到es时，默认的是当前的时间戳。于是需求就是将日志中的时间代替它生成的时间戳，开搞!<!--more--></p><div class="language-lua line-numbers-mode" data-ext="lua"><pre class="language-lua"><code><span class="token function">input</span> <span class="token punctuation">{</span>
    <span class="token function">file</span> <span class="token punctuation">{</span>
        path <span class="token operator">=</span><span class="token operator">&gt;</span> <span class="token punctuation">[</span> <span class="token string">&quot;/var/log/messages&quot;</span> <span class="token punctuation">]</span>
        start_position <span class="token operator">=</span><span class="token operator">&gt;</span> <span class="token string">&quot;beginning&quot;</span>
        sincedb_path <span class="token operator">=</span><span class="token operator">&gt;</span> <span class="token string">&quot;/dev/null&quot;</span>
    <span class="token punctuation">}</span>
<span class="token punctuation">}</span>
<span class="token function">filter</span> <span class="token punctuation">{</span>
        <span class="token function">grok</span> <span class="token punctuation">{</span>
            patterns_dir <span class="token operator">=</span><span class="token operator">&gt;</span>  <span class="token string">&quot;/data/logstash/config/conf.d/patterns&quot;</span>
            match <span class="token operator">=</span><span class="token operator">&gt;</span> <span class="token punctuation">[</span> <span class="token string">&quot;message&quot;</span><span class="token punctuation">,</span> <span class="token string">&quot;%{LOGTIME:logtime}&quot;</span> <span class="token punctuation">]</span>
            <span class="token punctuation">}</span>
        <span class="token function">date</span> <span class="token punctuation">{</span>
            match <span class="token operator">=</span><span class="token operator">&gt;</span> <span class="token punctuation">[</span><span class="token string">&quot;logtime&quot;</span><span class="token punctuation">,</span><span class="token string">&quot;yyyy-MM-dd HH:mm:ss&quot;</span><span class="token punctuation">]</span>
            timezone <span class="token operator">=</span><span class="token operator">&gt;</span> <span class="token string">&quot;Asia/Shanghai&quot;</span>
        <span class="token punctuation">}</span>
  			 <span class="token function">mutate</span><span class="token punctuation">{</span>remove_field <span class="token operator">=</span><span class="token operator">&gt;</span> <span class="token punctuation">[</span><span class="token string">&quot;logtime&quot;</span> <span class="token punctuation">]</span><span class="token punctuation">}</span>
<span class="token punctuation">}</span>
<span class="token function">output</span> <span class="token punctuation">{</span>
    <span class="token function">elasticsearch</span> <span class="token punctuation">{</span>
        hosts <span class="token operator">=</span><span class="token operator">&gt;</span> <span class="token punctuation">[</span><span class="token string">&quot;http://10.23.188.108:9200&quot;</span><span class="token punctuation">]</span>
        index <span class="token operator">=</span><span class="token operator">&gt;</span> <span class="token string">&quot;test_%{+YYYY-MM-dd}&quot;</span>
        user <span class="token operator">=</span><span class="token operator">&gt;</span> elastic
        password <span class="token operator">=</span><span class="token operator">&gt;</span> <span class="token string">&quot;*************&quot;</span>
    <span class="token punctuation">}</span>
<span class="token punctuation">}</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>以上，就是全部实现的配置了。看起来很简单，我被折腾好久。</p><p>原本的日志长成这样，需要提取出<code>2022-12-01 07:59:59</code></p><div class="language-text line-numbers-mode" data-ext="text"><pre class="language-text"><code>[log_type:other_log] [record_time:2022-12-01 07:59:59] [user:shusenwang] [group:/xiaohongshu.sh/xiaohongshu-sh/社区部/社区技术部/算法组/基础模型组/] [host_ip:10.23.145.24] [dst_ip:17.248.165.75] [serv:网络存储] [app:iCloud_Drive[浏览]] [site:未定义位置] [tm_type:/移动终端/Android系统移动终端] [net_action:记录] [url:-] [DNS:p112-contacts.icloud.com] [filename:-] [filetype:-] 
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>为了匹配到这个时间我写了一个正则到<code>/data/logstash/config/conf.d/patterns</code></p><div class="language-text line-numbers-mode" data-ext="text"><pre class="language-text"><code>LOGTIME \\d{4}-\\d{2}-\\d{2}\\s\\d{2}:\\d{2}:\\d{2}
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>整体思路就是，用这个LOGTIME，在message这个串儿中匹配，匹配出来的东西，就叫做logtime，然后date插件在logtime这个小串中匹配一个符合<code>yyyy-MM-dd HH:mm:ss</code>的小小串，就这个<code>yyyy-MM-dd HH:mm:ss</code>,一开始我并不知道写啥，查阅文章，还写了ISO8601的标准时间戳格式，后来看到一篇文章说date插件默认会把匹配到的时间转换成时间戳@timestamp，后来我一想既然它默认转成时间戳，那还需要我告诉它时间戳长成啥样吗？那肯定是告诉它你要把什么样的时间格式转成时间戳啦，不过我传入date的串就是logtime啊，我感觉上面的grok都多余了。直接用date插件就可以了，反正你喜欢找是吧，自己在message里面找吧！！！</p><div class="language-lua line-numbers-mode" data-ext="lua"><pre class="language-lua"><code><span class="token function">input</span> <span class="token punctuation">{</span>
    <span class="token function">file</span> <span class="token punctuation">{</span>
        path <span class="token operator">=</span><span class="token operator">&gt;</span> <span class="token punctuation">[</span> <span class="token string">&quot;/var/log/messages&quot;</span> <span class="token punctuation">]</span>
        start_position <span class="token operator">=</span><span class="token operator">&gt;</span> <span class="token string">&quot;beginning&quot;</span>
        sincedb_path <span class="token operator">=</span><span class="token operator">&gt;</span> <span class="token string">&quot;/dev/null&quot;</span>
    <span class="token punctuation">}</span>
<span class="token punctuation">}</span>
<span class="token function">filter</span> <span class="token punctuation">{</span>
        <span class="token function">date</span> <span class="token punctuation">{</span>
            match <span class="token operator">=</span><span class="token operator">&gt;</span> <span class="token punctuation">[</span><span class="token string">&quot;logtime&quot;</span><span class="token punctuation">,</span><span class="token string">&quot;yyyy-MM-dd HH:mm:ss&quot;</span><span class="token punctuation">]</span>
            timezone <span class="token operator">=</span><span class="token operator">&gt;</span> <span class="token string">&quot;Asia/Shanghai&quot;</span>
        <span class="token punctuation">}</span>
  			 <span class="token function">mutate</span><span class="token punctuation">{</span>remove_field <span class="token operator">=</span><span class="token operator">&gt;</span> <span class="token punctuation">[</span><span class="token string">&quot;logtime&quot;</span> <span class="token punctuation">]</span><span class="token punctuation">}</span>
<span class="token punctuation">}</span>
<span class="token function">output</span> <span class="token punctuation">{</span>
    <span class="token function">elasticsearch</span> <span class="token punctuation">{</span>
        hosts <span class="token operator">=</span><span class="token operator">&gt;</span> <span class="token punctuation">[</span><span class="token string">&quot;http://10.23.188.108:9200&quot;</span><span class="token punctuation">]</span>
        index <span class="token operator">=</span><span class="token operator">&gt;</span> <span class="token string">&quot;test_%{+YYYY-MM-dd}&quot;</span>
        user <span class="token operator">=</span><span class="token operator">&gt;</span> elastic
        password <span class="token operator">=</span><span class="token operator">&gt;</span> <span class="token string">&quot;*************&quot;</span>
    <span class="token punctuation">}</span>
<span class="token punctuation">}</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>我也是写这个记录的时候才想到的这个问题，没有实际实验过，以上内容自测哦。</p><p>附加，因为把时间戳替换成了过去的时间，所以在kibana查询最近的记录时会发现，咦，我日志呢？不用慌，它们回到了过去。</p><h2 id="参考文章" tabindex="-1"><a class="header-anchor" href="#参考文章" aria-hidden="true">#</a> 参考文章：</h2>`,12),r={href:"https://doc.yonyoucloud.com/doc/logstash-best-practice-cn/filter/date.html",target:"_blank",rel:"noopener noreferrer"},d={href:"https://wiki.eryajf.net/pages/3396.html#_1-date-filter-%E6%8F%92%E4%BB%B6",target:"_blank",rel:"noopener noreferrer"};function k(v,m){const s=c("ExternalLinkIcon");return o(),p("div",null,[u,n("p",null,[n("a",r,[a("logstash最佳实践--时间处理"),t(s)])]),n("p",null,[n("a",d,[a("logstash采集日志的时间格式探微"),t(s)])])])}const b=e(l,[["render",k],["__file","Logstash用日志时间代替时间戳.html.vue"]]);export{b as default};
